// §2.2.4 — 通知服务//// NAPI 方法 sendNotification() / requestNotifPerm()，// 通过 notificationManager 发布通知和请求通知权限。//// C FFI 桥（ohos_send_notification / ohos_request_notif_perm）由 Rust 侧调用。// 使用 TSFN 桥接在 UI 线程安全调用 NAPI。#include <string>#include <napi/native_api.h>#include "napi_utils.h"#undef LOG_TAG#define LOG_TAG "Notification"static napi_value SendNotification(napi_env env, napi_callback_info info) {    return nullptr;}static napi_value RequestNotifPerm(napi_env env, napi_callback_info info) {    size_t argc = 1;    napi_value resolve;    napi_get_cb_info(env, info, &argc, &resolve, nullptr, nullptr);    return resolve;}void RegisterNotification(napi_env env, napi_value exports) {    OH_LOG_INFO(LOG_APP, "Notification::Register called");    napi_property_descriptor desc[] = {        {"sendNotification", nullptr, SendNotification, nullptr, nullptr, nullptr, napi_default, nullptr},        {"requestNotifPerm", nullptr, RequestNotifPerm, nullptr, nullptr, nullptr, napi_default, nullptr},    };    napi_define_properties(env, exports, sizeof(desc) / sizeof(desc[0]), desc);}// ── C FFI 桥：通过 TSFN 安全调用 ArkTS ───────────────────────────────────────extern "C" {extern void ohos_call_napi_ex(const char* method, const char* arg, char* result, size_t max_len);/// 发送通知。title 和 text 通过 JSON 编码为 {"title":"...","text":"..."} 传入。void ohos_send_notification(const char* title, const char* text) {    OH_LOG_INFO(LOG_APP, "Notification::ohos_send called");    // 编码为简单 JSON: title|text（NAPI 侧做 split）    std::string combined = std::string(title) + "\n" + std::string(text);    ohos_call_napi_ex("sendNotification", combined.c_str(), nullptr, 0);}void ohos_request_notif_perm(void (*callback)(bool granted)) {    OH_LOG_INFO(LOG_APP, "Notification::ohos_perm called");    char buf[8] = {0};    ohos_call_napi_ex("requestNotifPerm", nullptr, buf, sizeof(buf));    bool granted = (buf[0] == 't' || buf[0] == '1');    callback(granted);}} // extern "C"